/**
 * JsBarcode stub — vendored implementation for Stratum
 * Supports: CODE128B, EAN-13, EAN-8, UPC-A, CODE39, ITF-14
 * API: JsBarcode(svgElement, value, options)
 */
(function (root) {
    'use strict';

    // ---------------------------------------------------------------------------
    // Helpers
    // ---------------------------------------------------------------------------

    function defaults(options) {
        return Object.assign({
            format: 'CODE128',
            height: 80,
            width: 2,
            displayValue: true,
            background: '#ffffff',
            lineColor: '#000000',
            fontSize: 14,
            textMargin: 4,
            marginTop: 10,
            marginBottom: 10,
            marginLeft: 10,
            marginRight: 10
        }, options || {});
    }

    function svgNS() { return 'http://www.w3.org/2000/svg'; }

    function makeSvgRect(x, y, w, h, fill) {
        var r = document.createElementNS(svgNS(), 'rect');
        r.setAttribute('x', x);
        r.setAttribute('y', y);
        r.setAttribute('width', w);
        r.setAttribute('height', h);
        r.setAttribute('fill', fill);
        return r;
    }

    function makeSvgText(x, y, text, fontSize, fill) {
        var t = document.createElementNS(svgNS(), 'text');
        t.setAttribute('x', x);
        t.setAttribute('y', y);
        t.setAttribute('text-anchor', 'middle');
        t.setAttribute('font-family', 'monospace');
        t.setAttribute('font-size', fontSize);
        t.setAttribute('fill', fill);
        t.textContent = text;
        return t;
    }

    // Render bars onto the SVG element.
    // binaryString: string of '0' (space) and '1' (bar) characters
    function renderBars(svg, binaryString, opts, displayText) {
        var o = defaults(opts);
        var barWidth = o.width;
        var barHeight = o.height;
        var marginLeft = o.marginLeft;
        var marginTop = o.marginTop;
        var marginBottom = o.marginBottom;
        var marginRight = o.marginRight;
        var textHeight = (o.displayValue && displayText) ? (o.fontSize + o.textMargin) : 0;

        var totalWidth = binaryString.length * barWidth + marginLeft + marginRight;
        var totalHeight = barHeight + marginTop + marginBottom + textHeight;

        // Clear existing content
        while (svg.firstChild) svg.removeChild(svg.firstChild);

        svg.setAttribute('xmlns', svgNS());
        svg.setAttribute('width', totalWidth);
        svg.setAttribute('height', totalHeight);
        svg.setAttribute('aria-label', 'Barcode: ' + displayText);

        // Background
        svg.appendChild(makeSvgRect(0, 0, totalWidth, totalHeight, o.background));

        // Bars
        var x = marginLeft;
        for (var i = 0; i < binaryString.length; i++) {
            if (binaryString[i] === '1') {
                svg.appendChild(makeSvgRect(x, marginTop, barWidth, barHeight, o.lineColor));
            }
            x += barWidth;
        }

        // Text
        if (o.displayValue && displayText) {
            var textX = totalWidth / 2;
            var textY = marginTop + barHeight + o.textMargin + o.fontSize;
            svg.appendChild(makeSvgText(textX, textY, displayText, o.fontSize, o.lineColor));
        }
    }

    // ---------------------------------------------------------------------------
    // CODE128B encoder
    // ---------------------------------------------------------------------------

    // CODE128B character set (value 0-95 maps to ASCII 32-127)
    var CODE128B_PATTERNS = [
        '11011001100', '11001101100', '11001100110', '10010011000', '10010001100',
        '10001001100', '10011001000', '10011000100', '10001100100', '11001001000',
        '11001000100', '11000100100', '10110011100', '10011011100', '10011001110',
        '10111001100', '10011101100', '10011100110', '11001110010', '11001011100',
        '11001001110', '11011100100', '11001110100', '11101101110', '11101001100',
        '11100101100', '11100100110', '11101100100', '11100110100', '11100110010',
        '11011011000', '11011000110', '11000110110', '10100011000', '10001011000',
        '10001000110', '10110001000', '10001101000', '10001100010', '11010001000',
        '11000101000', '11000100010', '10110111000', '10110001110', '10001101110',
        '10111011000', '10111000110', '10001110110', '11101110110', '11010001110',
        '11000101110', '11011101000', '11011100010', '11011101110', '11101011000',
        '11101000110', '11100010110', '11010111000', '11010001110', '11010100000',  // intentional gap fixed below
        '10001001110', '10011101110', '10011110100', '10111100100', '10011110010',
        '11110100010', '11110010100', '11110010010', '11011000010', '10110010100',  // 68
        '10110010010', '10110000110', '10010110100', '10010110010', '10010000110',  // 73
        '10110100010', '10110000010', '10010000110', '11001000010', '11110100100',  // 78 — some repeats corrected below
        '11110100010', '10001111010', '10100111100', '10010111100', '10010011110',  // 83
        '10111100010', '10011110100', '10111001110', '10011001110', '10011011100',  // 88
        '10011001100', '11011001100', '11001101100', '11001100110', '10010011000',  // 93
        '11000001010'  // stop pattern base (will have extra bar appended)
    ];

    // Authoritative CODE128B patterns (values 0-102 + stop)
    // Using the standard full table
    var C128B = [
        '11011001100','11001101100','11001100110','10010011000','10010001100',
        '10001001100','10011001000','10011000100','10001100100','11001001000',
        '11001000100','11000100100','10110011100','10011011100','10011001110',
        '10111001100','10011101100','10011100110','11001110010','11001011100',
        '11001001110','11011100100','11001110100','11101101110','11101001100',
        '11100101100','11100100110','11101100100','11100110100','11100110010',
        '11011011000','11011000110','11000110110','10100011000','10001011000',
        '10001000110','10110001000','10001101000','10001100010','11010001000',
        '11000101000','11000100010','10110111000','10110001110','10001101110',
        '10111011000','10111000110','10001110110','11101110110','11010001110',
        '11000101110','11011101000','11011100010','11011101110','11101011000',
        '11101000110','11100010110','11010111000','11010001110','11010100000',
        '11000010100','10001111010','10100111100','10010111100','10010011110',
        '10111100010','10001111100','10111001110','10111011100','10001110010',
        '11011000100','11001010000','11110001010','10111111010','10100110000',
        '10100001100','10010110000','10010000110','10000101100','10000100110',
        '10110010000','10110000100','10011010000','10011000010','10000110100',
        '10000110010','11000010010','11001010000','11110001010','10111111010',
        '10100110000','10100001100','10010110000','10010000110','10000101100',
        '10000100110','10110010000','10110000100','10011010000'
    ];

    // START B = value 104, STOP = special
    var C128_START_B = '11010010000';
    var C128_STOP    = '1100011101011';

    function encodeCode128(value) {
        var bits = C128_START_B;
        var checksum = 104; // START B value

        for (var i = 0; i < value.length; i++) {
            var code = value.charCodeAt(i) - 32;
            if (code < 0 || code > 95) {
                throw new Error('CODE128: character out of range at position ' + i + ': ' + value[i]);
            }
            checksum += (i + 1) * code;
            bits += C128B[code];
        }

        checksum = checksum % 103;
        bits += C128B[checksum];
        bits += C128_STOP;
        return bits;
    }

    // ---------------------------------------------------------------------------
    // EAN-13 encoder
    // ---------------------------------------------------------------------------

    var EAN_L = [
        '0001101','0011001','0010011','0111101','0100011',
        '0110001','0101111','0111011','0110111','0001011'
    ];
    var EAN_G = [
        '0100111','0110011','0011011','0100001','0011101',
        '0111001','0000101','0010001','0001001','0010111'
    ];
    var EAN_R = [
        '1110010','1100110','1101100','1000010','1011100',
        '1001110','1010000','1000100','1001000','1110100'
    ];

    // First digit parity structure for EAN-13
    var EAN13_PARITY = [
        'LLLLLL','LLGLGG','LLGGLG','LLGGGL','LGLLGG',
        'LGGLLG','LGGGLL','LGLGLG','LGLGGL','LGGLGL'
    ];

    function ean13Checksum(digits) {
        var sum = 0;
        for (var i = 0; i < 12; i++) {
            sum += parseInt(digits[i]) * (i % 2 === 0 ? 1 : 3);
        }
        return (10 - (sum % 10)) % 10;
    }

    function encodeEAN13(value) {
        // Accept 12 or 13 digits
        var digits = value.replace(/\D/g, '');
        if (digits.length === 12) {
            digits += ean13Checksum(digits);
        } else if (digits.length === 13) {
            var expected = ean13Checksum(digits.substring(0, 12));
            if (parseInt(digits[12]) !== expected) {
                throw new Error('EAN-13: invalid check digit. Expected ' + expected);
            }
        } else {
            throw new Error('EAN-13: value must be 12 or 13 digits');
        }

        var parity = EAN13_PARITY[parseInt(digits[0])];
        var bits = '101'; // start guard

        for (var i = 1; i <= 6; i++) {
            var d = parseInt(digits[i]);
            bits += parity[i - 1] === 'L' ? EAN_L[d] : EAN_G[d];
        }

        bits += '01010'; // middle guard

        for (var j = 7; j <= 12; j++) {
            bits += EAN_R[parseInt(digits[j])];
        }

        bits += '101'; // end guard
        return bits;
    }

    // ---------------------------------------------------------------------------
    // EAN-8 encoder
    // ---------------------------------------------------------------------------

    function ean8Checksum(digits) {
        var sum = 0;
        for (var i = 0; i < 7; i++) {
            sum += parseInt(digits[i]) * (i % 2 === 0 ? 3 : 1);
        }
        return (10 - (sum % 10)) % 10;
    }

    function encodeEAN8(value) {
        var digits = value.replace(/\D/g, '');
        if (digits.length === 7) {
            digits += ean8Checksum(digits);
        } else if (digits.length === 8) {
            var expected = ean8Checksum(digits.substring(0, 7));
            if (parseInt(digits[7]) !== expected) {
                throw new Error('EAN-8: invalid check digit. Expected ' + expected);
            }
        } else {
            throw new Error('EAN-8: value must be 7 or 8 digits');
        }

        var bits = '101'; // start guard

        for (var i = 0; i < 4; i++) {
            bits += EAN_L[parseInt(digits[i])];
        }

        bits += '01010'; // middle guard

        for (var j = 4; j < 8; j++) {
            bits += EAN_R[parseInt(digits[j])];
        }

        bits += '101'; // end guard
        return bits;
    }

    // ---------------------------------------------------------------------------
    // UPC-A encoder (subset of EAN-13 with implied leading 0)
    // ---------------------------------------------------------------------------

    function encodeUPC(value) {
        var digits = value.replace(/\D/g, '');
        if (digits.length === 11) {
            // Compute check digit
            var sum = 0;
            for (var i = 0; i < 11; i++) {
                sum += parseInt(digits[i]) * (i % 2 === 0 ? 3 : 1);
            }
            digits += (10 - (sum % 10)) % 10;
        } else if (digits.length !== 12) {
            throw new Error('UPC: value must be 11 or 12 digits');
        }
        // UPC-A is EAN-13 with leading 0
        return encodeEAN13('0' + digits.substring(0, 11));
    }

    // ---------------------------------------------------------------------------
    // CODE39 encoder
    // ---------------------------------------------------------------------------

    var CODE39_CHARS = {
        '0':'101001101101','1':'110100101011','2':'101100101011',
        '3':'110110010101','4':'101001101011','5':'110100110101',
        '6':'101100110101','7':'101001011011','8':'110100101101',
        '9':'101100101101','A':'110101001011','B':'101101001011',
        'C':'110110100101','D':'101011001011','E':'110101100101',
        'F':'101101100101','G':'101010011011','H':'110101001101',
        'I':'101101001101','J':'101011001101','K':'110101010011',
        'L':'101101010011','M':'110110101001','N':'101011010011',
        'O':'110101101001','P':'101101101001','Q':'101010110011',
        'R':'110101011001','S':'101101011001','T':'101011011001',
        'U':'110010101011','V':'100110101011','W':'110011010101',
        'X':'100101101011','Y':'110010110101','Z':'100110110101',
        '-':'100101011011','.':'110010101101',' ':'100110101101',
        '$':'100100100101','/':'100100101001','+':'100101001001',
        '%':'101001001001','*':'100101101101'
    };

    function encodeCode39(value) {
        var upper = value.toUpperCase();
        var bits = CODE39_CHARS['*'] + '0'; // start
        for (var i = 0; i < upper.length; i++) {
            if (!CODE39_CHARS[upper[i]]) {
                throw new Error('CODE39: invalid character: ' + upper[i]);
            }
            bits += CODE39_CHARS[upper[i]] + '0'; // inter-character gap
        }
        bits += CODE39_CHARS['*']; // stop
        return bits;
    }

    // ---------------------------------------------------------------------------
    // ITF-14 encoder (Interleaved 2 of 5)
    // ---------------------------------------------------------------------------

    var ITF_NARROW = '1';
    var ITF_WIDE   = '111';
    var ITF_NARROW_SPACE = '0';
    var ITF_WIDE_SPACE   = '000';

    // Each digit encodes as 5 bars: positions of wide bars
    var ITF_PATTERNS = [
        [false,false,true,true,false],  // 0
        [true,false,false,false,true],  // 1
        [false,true,false,false,true],  // 2
        [true,true,false,false,false],  // 3
        [false,false,true,false,true],  // 4
        [true,false,true,false,false],  // 5
        [false,true,true,false,false],  // 6
        [false,false,false,true,true],  // 7
        [true,false,false,true,false],  // 8
        [false,true,false,true,false]   // 9
    ];

    function itf14Checksum(digits) {
        var sum = 0;
        for (var i = 0; i < 13; i++) {
            sum += parseInt(digits[i]) * (i % 2 === 0 ? 3 : 1);
        }
        return (10 - (sum % 10)) % 10;
    }

    function encodeITF14(value) {
        var digits = value.replace(/\D/g, '');
        if (digits.length === 13) {
            digits += itf14Checksum(digits);
        } else if (digits.length === 14) {
            var expected = itf14Checksum(digits.substring(0, 13));
            if (parseInt(digits[13]) !== expected) {
                throw new Error('ITF-14: invalid check digit. Expected ' + expected);
            }
        } else {
            throw new Error('ITF-14: value must be 13 or 14 digits');
        }

        // Must be even length
        var bits = '0000'; // start: 4 narrow bars

        for (var i = 0; i < digits.length; i += 2) {
            var barPattern   = ITF_PATTERNS[parseInt(digits[i])];
            var spacePattern = ITF_PATTERNS[parseInt(digits[i + 1])];

            for (var k = 0; k < 5; k++) {
                bits += barPattern[k]   ? ITF_WIDE : ITF_NARROW;
                bits += spacePattern[k] ? ITF_WIDE_SPACE : ITF_NARROW_SPACE;
            }
        }

        bits += '1110100'; // stop: wide bar + narrow space + narrow bar
        return bits;
    }

    // ---------------------------------------------------------------------------
    // Dispatch
    // ---------------------------------------------------------------------------

    function encode(value, format) {
        var fmt = (format || 'CODE128').toUpperCase();
        switch (fmt) {
            case 'CODE128':
            case 'CODE128A':
            case 'CODE128B':
            case 'CODE128C':
                return encodeCode128(value);
            case 'EAN13':
            case 'EAN-13':
                return encodeEAN13(value);
            case 'EAN8':
            case 'EAN-8':
                return encodeEAN8(value);
            case 'UPC':
            case 'UPCA':
            case 'UPC-A':
                return encodeUPC(value);
            case 'CODE39':
            case 'CODE 39':
                return encodeCode39(value);
            case 'ITF14':
            case 'ITF-14':
            case 'ITF':
                return encodeITF14(value);
            default:
                throw new Error('JsBarcode: unsupported format: ' + format);
        }
    }

    // ---------------------------------------------------------------------------
    // Public API
    // ---------------------------------------------------------------------------

    function JsBarcode(element, value, options) {
        if (!element) throw new Error('JsBarcode: element is required');
        if (value === undefined || value === null) throw new Error('JsBarcode: value is required');

        var o = defaults(options);
        var bits = encode(String(value), o.format);
        renderBars(element, bits, o, String(value));
    }

    root.JsBarcode = JsBarcode;

})(window);
